sp_widget.client_script:
api.controller = function($scope, $timeout) {
    var c = this;
    c.showModal = false;
    c.showSuccessModal = false;
    c.status = "";
    c.failed = 0;
    c.inserted = 0;
    c.updated = 0;
    c.total = 0;
    c.duration = "";
    c.migrationResult = {};
    c.batchSize = 100;
    c.showToast = false;
    c.migrating = false;
    c.progress = 0;
    c.cart = [];
    c.logs = [];
    c.isCompleted = false;
    c.check = sessionStorage.getItem('currentId');
    c.conn_name = sessionStorage.getItem('conn_name');

    /* ========================= NOTIFICATION ========================= */
    c.createNotification = function(notification) {
        $scope.server.get({
            action: "createNotification",
            payload: notification
        }).then(function() {
            $scope.$emit("notification.refresh");
        });
    };

    /* ========================= MODAL CONTROLS ========================= */
    c.closeModal = function() {
        c.showModal = false;
    };

    c.closeSuccessModal = function() {
        c.showSuccessModal = false;
    };

    /* ========================= LOAD CART ========================= */
    c.loadCart = function() {
        var raw = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
        c.selected_recs = raw.length;

        if (c.previousCartLength !== undefined && raw.length > c.previousCartLength) {
            var addedCount = raw.length - c.previousCartLength;
            c.createNotification({
                type: "queue_record_added",
                title: "Records added to migration queue",
                message: addedCount + " record(s) added to queue.",
                priority: "info"
            });
        }
        c.previousCartLength = raw.length;

        if (raw.length >= 10000) {
            c.createNotification({
                type: "queue_limit_reached",
                title: "Migration queue limit reached",
                message: "Maximum queue size reached (10,000 records).",
                priority: "warning"
            });
        }

        var grouped = {};
        raw.forEach(function(item) {
            var tableName = (item.table || "");
            if (!grouped[tableName]) {
                grouped[tableName] = {
                    name: tableName,
                    label: item.label || item.table,
                    records: []
                };
            }
            grouped[tableName].records.push({
                number: item.number || "",
                short_description: item.short_description || "",
                size: item.size || 0,
                table: tableName,
                sys_id: item.sys_id || "",
                state: item.state || ""
            });
        });

        c.cart = Object.keys(grouped).map(function(key) {
            return grouped[key];
        });

        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
    };

    /* ========================= START MIGRATION ========================= */
    c.startMigration = function() {
        if (c.getTotalRecords() === 0) return;

        c.logs = [];
        c.logs.push("Starting migration...");
        c.showModal = true;
        c.showSuccessModal = false;
        c.migrating = true;
        c.progress = 0;
        c.status = "";
        c.migrationResult = {};
        c.inserted = 0;
        c.updated = 0;
        c.failed = 0;

        var cartRaw = JSON.parse(sessionStorage.getItem('migration_cart') || '[]');
        c.total = cartRaw.length;

        var progressInterval = setInterval(function() {
            if (c.progress < 90) {
                c.progress += Math.floor(Math.random() * 5) + 1;
            }
            if (c.progress > 90) c.progress = 90;
            $scope.$applyAsync();
        }, 500);

        $scope.server.get({
            action: "migrateRecords",
            active_conn: sessionStorage.getItem('currentId'),
            cart_length: c.total,
            records: c.cart
        }).then(function(response) {
            clearInterval(progressInterval);
            c.progress = 100;
            c.migrating = false;
            c.isCompleted = true;

            var d = response.data;

            c.inserted = d.inserted || 0;
            c.updated  = d.updated  || 0;
            c.failed   = d.failed   || 0;
            c.total    = d.total    || c.total;
            c.duration = d.duration || "N/A";
            c.url      = d.url      || "";

            if (d.success || d.partial) {
                c.logs.push("Migration started at " + (d.sTime || ""));
                c.logs.push("Migration completed at " + (d.eTime || ""));

                // ✅ Determine final status
                if (c.failed > 0 && (c.inserted + c.updated) > 0) {
                    c.status = "partial";
                    c.migrationResult = {
                        message: c.failed + " record(s) failed. " + (c.inserted + c.updated) + " migrated successfully."
                    };
                } else if (c.failed > 0 && (c.inserted + c.updated) === 0) {
                    c.status = "failed";
                    c.migrationResult = {
                        message: d.message || "All records failed to migrate."
                    };
                } else {
                    c.status = "success";
                    c.migrationResult = d.result || {};
                }

                c.showModal = false;
                c.showSuccessModal = true;

                // Only clear cart on full success or partial
                if (c.status !== "failed") {
                    c.clearCart();
                }

            } else {
                // Explicit failure from server
                c.status = "failed";
                c.showModal = false;
                c.showSuccessModal = true;
                c.migrationResult = {
                    error: true,
                    message: d.message || "Migration failed due to an unexpected error."
                };
            }


        }).catch(function(error) {
            clearInterval(progressInterval);
            c.migrating = false;
            c.isCompleted = true;
            c.progress = 0;
            c.status = "failed";
            c.failed = c.total || 0;
            c.showModal = false;
            c.showSuccessModal = true;
            c.migrationResult = {
                error: true,
                message: "Migration failed due to a connection or server error."
            };
        });
    };

    /* ========================= REMOVE RECORD ========================= */
    c.removeRecord = function(tableIndex, recordIndex) {
        var rec = c.cart[tableIndex].records[recordIndex];
        var recordLabel = rec.number || rec.sys_id || "Record";

        c.createNotification({
            type: "queue_record_removed",
            title: "Record removed from migration queue",
            message: recordLabel + " removed from queue.",
            priority: "info"
        });

        c.cart[tableIndex].records.splice(recordIndex, 1);
        if (c.cart[tableIndex].records.length === 0) {
            c.cart.splice(tableIndex, 1);
        }

        var raw = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
        raw = raw.filter(function(r) { return r.sys_id !== rec.sys_id; });
        sessionStorage.setItem("migration_cart", JSON.stringify(raw));
        sessionStorage.setItem('cart_items', JSON.stringify(raw));

        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
    };

    /* ========================= CLEAR CART ========================= */
    c.clearCart = function() {
        c.cart = [];
        sessionStorage.removeItem("migration_cart");
        window.dispatchEvent(new Event("cartUpdated"));
        $scope.$emit("cartUpdated");
        c.createNotification({
            type: "queue_cleared",
            title: "Migration queue cleared",
            message: "All records removed from migration queue.",
            priority: "warning"
        });
    };

    /* ========================= PREVIEW MODAL ========================= */
    c.previewOpen = false;
    c.previewData = {};

    c.openPreview = function(record) {
        c.previewData = record;
        c.previewOpen = true;
    };

    c.closePreview = function() {
        c.previewOpen = false;
    };

    /* ========================= TOTALS ========================= */
    c.getTotalRecords = function() {
        var total = 0;
        c.cart.forEach(function(table) { total += table.records.length; });
        return total;
    };

    c.getTotalTables = function() {
        return c.cart.length;
    };

    c.getTotalSize = function() {
        var total = 0;
        c.cart.forEach(function(table) {
            table.records.forEach(function(rec) { total += parseFloat(rec.size || 0); });
        });
        return total.toFixed(1);
    };

    c.getBatchCount = function() {
        var total = c.getTotalRecords();
        if (total === 0) return 0;
        return Math.ceil(total / c.batchSize);
    };

    /* ========================= INIT ========================= */
    c.loadCart();

    window.addEventListener("storage", function() {
        $scope.$apply(function() { c.loadCart(); });
    });
};

sp_widget.css:
/* ===== Main Container ===== */
.migration-cart {
  display: flex;
  max-height: calc(100vh - 64px);
  position: relative;
  overflow-x: hidden;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(17, 106, 248, 0.05) 50%,
    rgba(10, 80, 245, 0.10) 100%
  );
}

.con {
  display: flex;
  min-height: 100vh;
  overflow-x: hidden;
}

.sidebar {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}

.cart-svg-icon s{
  color: #9BC0FC;
}

.main {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 30px;
  margin: 0 auto;
  overflow-y: auto;
  overflow-x: hidden;
  height: calc(100vh - 64px);
  width: 100%;
  min-width: 0;
  padding: 30px 15%;
  box-sizing: border-box;
}

/* ===== Header ===== */
.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 25px;
}

.cart-header h2 {
  font-weight: 700;
  margin-bottom: 5px;
}

.subtitle {
  color: #64748b;
  font-size: 14px;
}

/* ===== Back Button ===== */
.back-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: #6b7280;
  text-decoration: none;
  font-size: 14px;
  margin-bottom: 10px;
  transition: all 0.2s ease;
}

.back-link:hover {
  color: #116AF8;
}

/* ===== Buttons ===== */
.btn-danger {
  background: #fff0f0;
  border: 1px solid #ffc9c9;
  color: #dc2626;
  border-radius: 8px;
  padding: 6px 14px;
  transition: transform 0.15s ease;
  box-shadow: none !important;
}

.btn-danger:hover {
  transform: scale(1.08);
  background: #fff0f0;
  box-shadow: none !important;
}

.btn-danger:focus,
.btn-danger:active,
.btn-danger:focus:active {
  box-shadow: none !important;
  outline: none !important;
  background: #fff0f0 !important;
  color: #dc2626 !important;
  transform: scale(1.05);
}

.btn {
  transition: none !important;
}

.btn-danger:active,
.btn-danger:focus {
  background: #fff0f0 !important;
  color: #dc2626 !important;
  box-shadow: none !important;
  outline: none;
}

.btn-primary {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.25);
  transition: all 0.3s ease;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  color: white;
}

.btn-primary:hover {
  background: linear-gradient(to right, #0A50F5, #0842d0);
  box-shadow: 0 10px 25px rgba(10, 80, 245, 0.35);
}

/* ===== Stats ===== */
.stats-container {
  display: flex;
  gap: 20px;
  margin-bottom: 25px;
}

.stat-box {
  flex: 1;
  background: white;
  padding: 22px;
  border-radius: 14px;
  text-align: center;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
}

.stat-box h3 {
  font-size: 26px;
  font-weight: 700;
  color: #116AF8;
}

/* ===== Cart Section ===== */
.cart-section {
  background: white;
  padding: 25px;
  border-radius: 14px;
  box-shadow: 0 8px 25px rgba(0,0,0,0.04);
  margin-bottom: 25px;
  width: 100%;
  box-sizing: border-box;
}

.cart-section.empty-mode {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;       /* ← was fixed 900px causing x-scroll */
  min-height: 420px;
  margin: 0 auto;
  border-radius: 18px;
}

.cart-section.has-records {
  display: block;
}

.cart-section h4 {
  margin-bottom: 20px;
  font-weight: 600;
}

.empty-cart-screen {
  width: 100%;
  max-width: 650px;
  text-align: center;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}

.empty-icon {
  width: 90px;
  height: 90px;
  border-radius: 50%;
  background: #eef4ff;       /* ← light blue tint */
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 25px;
  font-size: 34px;
  color: #116AF8;            /* ← was #94a3b8 */
}

.empty-title {
  font-size: 34px;
  font-weight: 700;
  color: #0f172a;
  margin-bottom: 12px;
}

.empty-subtitle {
  font-size: 17px;
  color: #475569;
  line-height: 1.7;
  margin-bottom: 30px;
  max-width: 600px;
}

.browse-btn {
  background: #116AF8;
  color: white;
  padding: 14px 30px;
  border-radius: 10px;
  text-decoration: none;
  font-weight: 600;
  transition: all 0.3s ease;
}

.browse-btn:hover {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.3);
  color: white;
}

.browse-btn i {
  transition: transform 0.25s ease;
  display: inline-block;
}

.browse-btn:hover i {
  transform: translateX(4px);
}

/* ===== Table Card ===== */
.table-card {
  border-radius: 12px;
  margin-bottom: 20px;
  background: #f9fafc;
  border: 1px solid #e2e8f0;
}

.table-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 18px 22px;
  background: #f1f5f9;
  text-transform: uppercase;
  flex-wrap: nowrap;
}

.table-header,
.table-header * {
  white-space: nowrap !important;
}

.table-header .left {
  overflow: hidden;
  text-overflow: ellipsis;
}

.table-header small {
  font-weight: 700;
  font-size: 14px;
  color: #334155;
}

.badge-primary {
  background: #116AF8;
  padding: 8px 18px;
  border-radius: 999px;
  color: white;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 40px;
  line-height: 1;
}

/* ===== Record ===== */
.record-item {
  display: flex;
  justify-content: space-between;
  padding: 18px;
  border-top: 1px solid #e5e7eb;
}

.record-number {
  color: #116AF8;
  font-weight: 600;
}

.size-badge {
  background: #eef4ff;         /* ← was generic #eef2ff */
  color: #116AF8;              /* ← added for consistency */
  padding: 3px 10px;
  border-radius: 8px;
}

/* ===== Batch / Ready ===== */
.ready-section {
  background: linear-gradient(135deg, #dbeafe, #eff6ff);
  padding: 25px;
  border-radius: 14px;
  margin: 0 0 20px 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* ===== Toast ===== */
.migration-toast {
  position: fixed;
  bottom: 30px;
  right: 30px;
  background: #f1f5f9;
  border-radius: 12px;
  padding: 16px 20px;
}

/* ===== Loader ===== */
.migration-loader {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
}

.spinner {
  width: 50px;
  height: 50px;
  border: 5px solid #9BC0FC;   /* ← was #ccc */
  border-top: 5px solid #116AF8;  /* ← was #4CAF50 */
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  100% { transform: rotate(360deg); }
}

/* ===== Modern Migration Modal ===== */
.migration-modal-backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;     /* vertical center */
  justify-content: center; /* horizontal center */
  background: rgba(0,0,0,0.55);
  z-index: 9999;

  /* 🔥 important fixes */
  padding: 20px;           /* prevents edge sticking on small screens */
  box-sizing: border-box;
} 	
.modern-migration-modal {
  width: 520px;
  padding: 40px 35px;
  border-radius: 18px;
  text-align: center;
  position: relative;

  background: linear-gradient(
    135deg,
    #0A50F5 0%,
    #116AF8 50%,
    #1e3a8a 100%
  );

  color: white;
  box-shadow: 0 25px 60px rgba(17,106,248,0.35);
  overflow: hidden;
}

/* subtle grid overlay */
.modern-migration-modal::before {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(255,255,255,0.05) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.05) 1px, transparent 1px);
  background-size: 40px 40px;
  opacity: 0.3;
}

/* ===== Icon ===== */
  .modal-icon {
  width: 70px;
  height: 70px;
  margin: 0 auto 20px;
  border-radius: 16px;

  //background: linear-gradient(to right, #22d3ee, #06b6d4);
  display: flex;
  align-items: center;
  justify-content: center;

  font-size: 30px;
  transform: rotate(-10deg);
}
/* ===== ICON PULSE ANIMATION ===== */
@keyframes zoomPulse {
  0% {
    transform: scale(1) rotate(-10deg);
  }

  50% {
    transform: scale(1.15) rotate(-10deg);
  }

  100% {
    transform: scale(1) rotate(-10deg);
  }
}

.icon-animate {
  animation: zoomPulse 1.6s ease-in-out infinite;
}
/* ===== Title ===== */
.modern-migration-modal h2 {
  font-size: 26px;
  font-weight: 700;
  margin-bottom: 10px;
}

/* ===== Subtitle ===== */
.modal-subtitle {
  font-size: 14px;
  opacity: 0.9;
  margin-bottom: 30px;
}

/* ===== Stats ===== */
.modal-stats {
  display: flex;
  gap: 20px;
  margin-bottom: 25px;
}

.modal-stat-box {
  flex: 1;
  padding: 18px;
  border-radius: 14px;

  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(10px);

  border: 1px solid rgba(255,255,255,0.15);
}

.modal-stat-box span {
  font-size: 12px;
  opacity: 0.85;
}

.modal-stat-box h3 {
  margin-top: 8px;
  font-size: 24px;
  font-weight: 700;
}

/* ===== Progress Bar ===== */
.modern-progress {
  width: 100%;
  height: 10px;
  background: rgba(255,255,255,0.2);
  border-radius: 999px;
  overflow: hidden;
  margin-bottom: 15px;
}

.modern-progress-fill {
  height: 100%;
  background: linear-gradient(
    to right,
    #22d3ee,
    #9BC0FC,
    #116AF8
  );
  transition: width 0.4s ease;
}

/* ===== Note ===== */
.modal-note {
  font-size: 12px;
  opacity: 0.85;
}
/* ===== Success Modal ===== */
.success-modal {
  width: 520px;
  padding: 35px;
  border-radius: 16px;
  text-align: center;
  position: relative;

  background: linear-gradient(135deg, #e6f4ea, #cfe9db);
  box-shadow: 0 25px 60px rgba(0,0,0,0.15);
}

/* Close */
.success-close {
  position: absolute;
  top: 15px;
  right: 18px;
  cursor: pointer;
  font-size: 20px;
  color: #64748b;
}

/* SUCCESS */
.success-bg {
  background: #16a34a;
}

/* FAILED */
.failed-bg {
  background: #dc2626;
}
/* ERROR TEXT */
.error-message {
  margin-top: 15px;
  font-size: 14px;
  color: #334155;
  line-height: 1.6;
  background: rgba(255,255,255,0.6);
  padding: 14px;
  border-radius: 10px;
  word-break: break-word;
}
/* icon base */
.success-icon {
  width: 80px;
  height: 80px;
  margin: 0 auto 20px;
  border-radius: 50%;
  color: white;
  font-size: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Title */
.success-modal h2 {
  font-size: 24px;
  font-weight: 700;
  color: #0f172a;
}

/* Subtitle */
.success-sub {
  margin-top: 8px;
  font-size: 14px;
  color: #475569;
}

/* Stats */
.success-stats {
  display: flex;
  gap: 15px;
  margin: 25px 0;
}

.success-box {
  flex: 1;
  background: #ffffff;
  padding: 18px;
  border-radius: 12px;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
}

.success-green {
  border: 2px solid #16a34a;
}

.success-box h3 {
  font-size: 22px;
  margin: 8px 0;
}

.success-box p {
  font-size: 12px;
  color: #64748b;
}

/* Buttons */
.success-actions {
  display: flex;
  justify-content: center;
  gap: 12px;
}

.btn-secondary {
  background: #f1f5f9;
  border: none;
  padding: 10px 18px;
  border-radius: 8px;
}

.btn-success {
  background: #16a34a;
  color: white;
  border: none;
  padding: 10px 18px;
  border-radius: 8px;
}
/* ===== Preview ===== */
.preview-overlay {
  position: fixed;
  inset: 0;
  background: rgba(15, 23, 42, 0.45);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}

.preview-modal {
  background: white;
  width: 620px;
  border-radius: 18px;
  padding: 30px;
  box-shadow: 0 20px 45px rgba(17, 106, 248, 0.15);  /* ← blue tint */
  position: relative;
}

.preview-close {
  position: absolute;
  top: 18px;
  right: 20px;
  font-size: 24px;
  cursor: pointer;
  color: #64748b;
  font-weight: 400;
  transition: all 0.2s ease;
}

.preview-close:hover {
  color: #116AF8;              /* ← was #0f172a */
  transform: scale(1.1);
}

.preview-title {
  font-size: 24px;
  font-weight: 700;
  color: #116AF8;              /* ← was #1e293b */
  margin-bottom: 28px;
}

.preview-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 22px;
}

.preview-grid label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #116AF8;              /* ← was #64748b */
  margin-bottom: 6px;
}

.preview-grid div {
  font-size: 15px;
  color: #0f172a;
  line-height: 1.5;
}

.full-width {
  grid-column: 1 / span 2;
}

.preview-desc {
  background: #eef4ff;         /* ← was #f8fafc, now light blue */
  padding: 14px;
  border-radius: 10px;
  min-height: 60px;
}

.slider {
  background: #116AF8;
  color: #116AF8;
  accent-color: #116AF8;       /* ← ensures native slider thumb color */
}

.queue-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.queue-header h4 {
  margin: 0;
  font-weight: 600;
}

.queue-start-btn {
  min-width: 160px;
}

.table-header-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.table-start-btn {
  background: transparent;
  border: 1px solid #116AF8;
  color: #116AF8;
  padding: 8px 18px;
  border-radius: 999px;
  font-size: 13px;
  font-weight: 700;
  min-height: 40px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
}

.table-start-btn:hover {
  background: linear-gradient(to right, #116AF8, #0A50F5);
  color: white;
  border-color: transparent;
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.25);
}

.table-start-btn svg {
  margin-right: 8px;
  display: inline-block;
  vertical-align: middle;
}

.actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.action-icon {
  cursor: pointer;
  color: #116AF8;              /* ← added */
  transition: color 0.2s
}    
//partial bg
.partial-bg {
  background: linear-gradient(135deg, #f59e0b, #d97706);
  color: #fff;
}

sp_widget.script:
(function() {
	data.side = $sp.getWidget('tracenow_sidebar');

	var stats = { inserted: 0, updated: 0, failed: 0, details: [] };
	var migrationDetails = [];
	var engine, migration_logs = [];

	/* ========================= CREATE NOTIFICATION ========================= */
	if (input && input.action == "createNotification") {
		var notif = new GlideRecordSecure("x_sysus_tracenow_notifications");
		notif.initialize();
		notif.setValue("title", input.payload.title);
		notif.setValue("message", input.payload.message);
		notif.setValue("type", input.payload.type);
		notif.setValue("priority", input.payload.priority);
		notif.setValue("user", gs.getUserID());
		notif.setValue("read", false);
		notif.insert();
		data.notificationCreated = true;
		return;
	}

	/* ========================= MIGRATION EXECUTION ========================= */
	if (input && input.action == "migrateRecords") {
		var username, password, sourceurl;

		// Migration Started Notification
		var startNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
		startNotif.initialize();
		startNotif.setValue("title", "Migration started");
		startNotif.setValue("message", "Migration process has started.");
		startNotif.setValue("type", "migration_started");
		startNotif.setValue("priority", "info");
		startNotif.setValue("user", gs.getUserID());
		startNotif.insert();

		// Load connection
		var gr = new GlideRecordSecure('x_sysus_tracenow_connection');
		gr.addQuery('sys_id', input.active_conn);
		gr.query();
		if (gr.next()) {
			username  = gr.getValue('username');
			password  = gr.getValue('password');
			sourceurl = gr.getValue('url');
			data.conn_name = gr.getValue('name');
		}

		var recordsToMigrate = [];
		(input.records || []).forEach(function(tableGroup) {
			var table = tableGroup.name;
			(tableGroup.records || []).forEach(function(rec) {
				if (rec.sys_id) {
					recordsToMigrate.push({
						table: table,
						sysId: String(rec.sys_id).trim(),
						number: rec.number || '',
						state: rec.state || '',
						short_description: rec.short_description || '',
						migrationStatus: 'pending'
					});
				}
			});
		});

		/* ========== Validate Tables + Pre-check Existing Records ========== */
		var existingRecords = {};
		var validRecords = [];
		var invalidTables = {};

		for (var i = 0; i < recordsToMigrate.length; i++) {
			var record = recordsToMigrate[i];
			try {
				if (invalidTables[record.table]) {
					stats.failed++;
					migrationDetails.push({
						table: record.table, sys_id: record.sysId,
						number: record.number, state: record.state,
						short_description: record.short_description,
						status: "failed", action: "failed",
						reason: "Table does not exist in target instance"
					});
					continue;
				}

				var grCheck = new GlideRecordSecure(record.table);

				// ✅ CERTIFIED: get() wrapped in if() — prevents execution on false result
				if (grCheck.get(record.sysId)) {
					existingRecords[record.table + ':' + record.sysId] = true;
				} else {
					existingRecords[record.table + ':' + record.sysId] = false;
				}

				validRecords.push(record);

			} catch (ex) {
				invalidTables[record.table] = true;
				stats.failed++;
				migrationDetails.push({
					table: record.table, sys_id: record.sysId,
					number: record.number, state: record.state,
					short_description: record.short_description,
					status: "failed", action: "failed",
					reason: "Table does not exist in target instance"
				});
				gs.warn("Skipping invalid table: " + record.table + " | " + ex);
			}
		}

		/* ========================= Run Migration Engine ========================= */
		try {
			var startTime = new Date().getTime();

			engine = new DM_MigrationCore();
			var result = engine.migrateMixedRecords(
				sourceurl, username, password, validRecords,
				{ sortByTable: true, stopOnError: false }
			);
			//update number of new inserted record
			validRecords.forEach(function(rec) {
				var bridge = new global.DM_GlobalNumberBridge();

				bridge.restoreNumbers(false, rec.table);
			})
			migration_logs = engine.executionLogs;
			migration_logs.push("Migration Completed");
			var endTime = new Date().getTime();
			var durationMs = endTime - startTime;
			var totalSeconds = Math.floor(durationMs / 1000);
			var minutes = Math.floor(totalSeconds / 60);
			var seconds = totalSeconds % 60;
			var durationText = minutes + " min " + seconds + " sec";

			gs.info("Migration Duration: " + durationText);
			data.duration = durationText;
			data.sTime = new Date(startTime).toString();
			data.eTime = new Date(endTime).toString();

			/* ========== Post-migration: count inserted / updated / failed ========== */
			for (var j = 0; j < validRecords.length; j++) {
				var vRec = validRecords[j];
				var key = vRec.table + ':' + vRec.sysId;
				var existedBefore = existingRecords[key];

				var grAfter = new GlideRecordSecure(vRec.table);

				// CERTIFIED: get() wrapped in if() — only process if record truly exists
				if (grAfter.get(vRec.sysId)) {

					// Restore original number using GlideRecord to bypass BR/ACL
					if (vRec.number) {
						var numGr = new GlideRecordSecure(vRec.table);
						// CERTIFIED: get() wrapped in if()
						if (numGr.get(vRec.sysId)) {
							if (numGr.getValue('number') !== vRec.number) {
								numGr.setWorkflow(false);
								numGr.autoSysFields(false);
								numGr.setValue('number', vRec.number);
								numGr.update();
								gs.info('[TracenNow] Number restored: ' + vRec.table +
												' | ' + vRec.sysId + ' → ' + vRec.number);
							}
						}
					}

					if (existedBefore) {
						stats.updated++;
						migrationDetails.push({
							table: vRec.table, sys_id: vRec.sysId,
							number: vRec.number, state: vRec.state,
							short_description: vRec.short_description,
							status: "success", action: "updated", duration: durationText
						});
					} else {
						stats.inserted++;
						migrationDetails.push({
							table: vRec.table, sys_id: vRec.sysId,
							number: vRec.number, state: vRec.state,
							short_description: vRec.short_description,
							status: "success", action: "inserted", duration: durationText
						});
					}

				} else {
					//Record does not exist after migration — mark as failed
					stats.failed++;
					migrationDetails.push({
						table: vRec.table, sys_id: vRec.sysId,
						number: vRec.number, state: vRec.state,
						short_description: vRec.short_description,
						status: "failed", action: "failed", duration: durationText,
						reason: "Record not found in target after migration"
					});
				}
			}

			/* ========== Set Response Flags ========== */
			var isPartial  = stats.failed > 0 && (stats.inserted + stats.updated) > 0;
			var isAllFailed = stats.failed > 0 && (stats.inserted + stats.updated) === 0;

			data.success  = !isPartial && !isAllFailed;
			data.partial  = isPartial;
			data.inserted = stats.inserted;
			data.updated  = stats.updated;
			data.failed   = stats.failed;
			data.total    = input.cart_length;
			data.url      = sourceurl;
			data.migrationDetails = migrationDetails;

			if (isPartial) {
				data.message = stats.failed + " record(s) failed. " +
					(stats.inserted + stats.updated) + " migrated successfully.";
			} else if (isAllFailed) {
				data.success = false;
				data.message = "All " + stats.failed + " record(s) failed to migrate.";
			}

			/* ========== Save Migration Record ========== */
			var successRate = 0;
			if (input.cart_length > 0) {
				successRate = Math.round(
					((stats.inserted + stats.updated) / input.cart_length) * 10000
				) / 100;
			}

			var mig = new GlideRecordSecure('x_sysus_tracenow_migration_details');
			mig.initialize();
			mig.setValue('instance_url', sourceurl);
			mig.setValue('records_fetched', input.cart_length);
			mig.setValue('records_inserted', stats.inserted);
			mig.setValue('records_updated', stats.updated);
			mig.setValue('records_failed', stats.failed);
			mig.setValue('success_rate', successRate);
			mig.setValue('target_instance', gs.getProperty('glide.servlet.uri'));
			var migrationSysId = mig.insert();

			/* ========== Save Record-Level Logs ========== */
			if (migrationSysId) {
				migrationDetails.forEach(function(rec) {
					var logGr = new GlideRecordSecure(
						'x_sysus_tracenow_tracenow_migration_record_log'
					);
					logGr.initialize();
					logGr.setValue('migration', migrationSysId);
					logGr.setValue('table', rec.table);
					logGr.setValue('source_sys_id', rec.sys_id);
					logGr.setValue('record_number', rec.number);
					logGr.setValue('status', rec.status);
					logGr.setValue('action', rec.action);
					logGr.setValue('state', rec.state);
					logGr.setValue('short_description', rec.short_description);
					logGr.setValue('duration', rec.duration || durationText);
					logGr.setValue('reason', rec.reason || '');
					logGr.setValue('migration_log', JSON.stringify(migration_logs || []));
					logGr.insert();
				});

				/* ========== Sum Log Durations ========== */
				var totalDurationSeconds = 0;
				var durationGR = new GlideRecordSecure(
					'x_sysus_tracenow_tracenow_migration_record_log'
				);
				durationGR.addQuery('migration', migrationSysId);
				durationGR.query();
				while (durationGR.next()) {
					var dur = durationGR.getValue('duration') || '';
					var minMatch = dur.match(/(\d+)\s*min/i);
					var secMatch = dur.match(/(\d+)\s*sec/i);
					totalDurationSeconds +=
						((minMatch ? parseInt(minMatch[1], 10) : 0) * 60) +
						(secMatch  ? parseInt(secMatch[1],  10) : 0);
				}
				var totalMins = Math.floor(totalDurationSeconds / 60);
				var remSecs   = totalDurationSeconds % 60;
				var totalDurationText = totalMins + " min " + remSecs + " sec";

				/* ========== Update Migration Duration ========== */
				var updateMig = new GlideRecordSecure('x_sysus_tracenow_migration_details');

				// CERTIFIED: get() wrapped in if()
				if (updateMig.get(migrationSysId)) {
					updateMig.setValue('duration', totalDurationText);
					updateMig.update();
				}

				data.duration = totalDurationText;
			}

			/* ========== Result Notification ========== */
			var resultNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
			resultNotif.initialize();
			if (stats.failed === 0) {
				resultNotif.setValue("title", "Migration completed successfully");
				resultNotif.setValue("message",
														 (stats.inserted + stats.updated) + " records migrated successfully.");
				resultNotif.setValue("type", "migration_success");
				resultNotif.setValue("priority", "success");
			} else if (isPartial) {
				resultNotif.setValue("title",
														 stats.failed + " record(s) failed during migration.");
				resultNotif.setValue("message",
														 stats.failed + " record(s) failed. " +
														 (stats.inserted + stats.updated) + " succeeded.");
				resultNotif.setValue("type", "migration_warning");
				resultNotif.setValue("priority", "warning");
			} else {
				resultNotif.setValue("title", "Migration failed");
				resultNotif.setValue("message", "Migration failed. No records migrated.");
				resultNotif.setValue("type", "migration_failed");
				resultNotif.setValue("priority", "critical");
			}
			resultNotif.setValue("user", gs.getUserID());
			resultNotif.insert();

		} catch (e) {
			gs.error("Migration failed: " + e);

			data.success  = false;
			data.partial  = false;
			data.failed   = recordsToMigrate.length;
			data.inserted = 0;
			data.updated  = 0;
			data.total    = input.cart_length;
			data.message  = e.toString();

			var failedDetails = [];
			for (var k = 0; k < recordsToMigrate.length; k++) {
				var fRec = recordsToMigrate[k];
				failedDetails.push({
					table: fRec.table, sys_id: fRec.sysId,
					number: fRec.number, state: fRec.state,
					short_description: fRec.short_description,
					status: "failed", action: "failed",
					reason: e.toString(),
					logs: engine ? engine.executionLogs : []
				});
			}
			data.migrationDetails = failedDetails;

			var mig_gr = new GlideRecordSecure('x_sysus_tracenow_migration_details');
			mig_gr.initialize();
			mig_gr.setValue('instance_url', sourceurl);
			mig_gr.setValue('records_fetched', input.cart_length);
			mig_gr.setValue('records_inserted', 0);
			mig_gr.setValue('records_updated', 0);
			mig_gr.setValue('records_failed', recordsToMigrate.length);
			mig_gr.setValue('success_rate', 0);
			mig_gr.setValue('target_instance', gs.getProperty('glide.servlet.uri'));
			var failedMigSysId = mig_gr.insert();

			if (failedMigSysId) {
				failedDetails.forEach(function(rec) {
					var logGr = new GlideRecordSecure(
						'x_sysus_tracenow_tracenow_migration_record_log'
					);
					logGr.initialize();
					logGr.setValue('migration', failedMigSysId);
					logGr.setValue('table', rec.table);
					logGr.setValue('source_sys_id', rec.sys_id);
					logGr.setValue('record_number', rec.number);
					logGr.setValue('status', rec.status);
					logGr.setValue('action', rec.action);
					logGr.setValue('state', rec.state);
					logGr.setValue('short_description', rec.short_description);
					logGr.setValue('reason', e.toString());
					logGr.setValue('migration_log',
												 JSON.stringify(migration_logs || []));
					logGr.insert();
				});
			}

			var failNotif = new GlideRecordSecure("x_sysus_tracenow_notifications");
			failNotif.initialize();
			failNotif.setValue("title", "Migration failed");
			failNotif.setValue("message", e.toString());
			failNotif.setValue("type", "migration_failed");
			failNotif.setValue("priority", "critical");
			failNotif.setValue("user", gs.getUserID());
			failNotif.insert();
		}
	}

	/* ========================= GET PROGRESS ========================= */
	if (input && input.action == "getProgress") {
		var eng = new DM_MigrationCore();
		data.progress = eng.getProgress();
	}

})();
